const runtimeWindow = window;
const runtimeDocument = runtimeWindow.document;
const hostWindow = (() => {
  try {
    return window.top && window.top.document ? window.top : window;
  } catch {
    return window;
  }
})();
const hostDocument = hostWindow.document;

const inlineMessageSelectors = [
  '#chat > .mes:last-child .mes_text',
  '#chat > .mes_block:last-child .mes_text',
  '#chat .mes:last-child .mes_text',
  '.mes_block:last-child .mes_text',
  '.mes:last-child .mes_text',
];

const inlineContainerSelectors = [
  '#chat',
  '#chat2',
  '#chat_display',
  '#chat_container',
  '.chat',
  '#sheld',
];

const findInlinePlacement = () => {
  for (const selector of inlineMessageSelectors) {
    const element = hostDocument.querySelector(selector);
    if (element) {
      return { type: 'append', element };
    }
  }

  for (const selector of inlineContainerSelectors) {
    const element = hostDocument.querySelector(selector);
    if (element) {
      return { type: 'append', element };
    }
  }

  return null;
};

const placeHostElement = hostElement => {
  const layout = hostElement.getAttribute('data-layout');
  if (layout === 'inline') {
    const placement = findInlinePlacement();
    if (placement?.type === 'after' && placement.element?.parentElement) {
      if (placement.element.nextElementSibling !== hostElement) {
        placement.element.insertAdjacentElement('afterend', hostElement);
      }
      return;
    }

    if (placement?.type === 'append') {
      if (placement.element.lastElementChild !== hostElement) {
        placement.element.appendChild(hostElement);
      }
      return;
    }
  }

  hostDocument.body.appendChild(hostElement);
};

runtimeDocument.getElementById("cultivation-world-status-bar-module")?.remove();
hostDocument.getElementById("cultivation-world-status-bar-host")?.remove();

const hostElement = hostDocument.createElement('div');
hostElement.id = "cultivation-world-status-bar-host";
hostElement.setAttribute('data-layout', 'fab');
hostElement.setAttribute('script_id', typeof getScriptId === 'function' ? getScriptId() : "89e4c136-2e4e-4be8-9f71-7b3fe3a4fd91");
hostElement.setAttribute('title', "修仙世界状态栏");

const shadowRoot = hostElement.attachShadow({ mode: 'open' });
const styleElement = hostDocument.createElement('style');
